```class Solution {
    public int integerReplacement(int n) {
        if (n == 1) return 0;
        if (n == 2) return 1;
        int result = n;
        while (result != 1) {
            if (result % 2 == 0) {
                result /= 2;
            } else {
                result = (result + 1) % 2;
            }
        }
        return result;
    }
}
```

